const avvio = require('..')()

function a (instance, opts, cb) {
  (opts.use || []).forEach(_ => { instance.use(_, { use: opts.subUse || [] }) })
  setTimeout(cb, 10)
}
const pointer = a

function b (instance, opts, cb) {
  (opts.use || []).forEach(_ => { instance.use(_, { use: opts.subUse || [] }) })
  setTimeout(cb, 20)
}

function c (instance, opts, cb) {
  (opts.use || []).forEach(_ => { instance.use(_, { use: opts.subUse || [] }) })
  setTimeout(cb, 30)
}

avvio
  .use(first, { hello: 'world' })
  .use(duplicate, { count: 0 })
  .use(function a (instance, opts, cb) {
    instance.use(pointer, { use: [b], subUse: [c] })
      .use(b)
    setTimeout(cb, 42)
  })
  .after(function (err, cb) {
    if (err) {
      console.log('something bad happened')
      console.log(err)
    }
    console.log('after first and second')
    cb()
  })
  .use(duplicate, { count: 4 })
  .use(third)
  .ready(function (err) {
    if (err) {
      throw err
    }
    console.log('application booted!')
  })

avvio.on('preReady', () => {
  console.log(avvio.prettyPrint())
})

function first (instance, opts, cb) {
  console.log('first loaded', opts)
  instance.use(second)
  setTimeout(cb, 42)
}

function second (instance, opts, cb) {
  console.log('second loaded')
  process.nextTick(cb)
}

function third (instance, opts, cb) {
  console.log('third loaded')
  cb()
}

function duplicate (instance, opts, cb) {
  console.log('duplicate loaded', opts.count)
  if (opts.count > 0) {
    instance.use(duplicate, { count: opts.count - 1 })
  }
  setTimeout(cb, 20)
}

import { FastifyInstance } from 'fastify'
import { Knex } from 'knex'
import fp from 'fastify-plugin'
import { Auth } from '../../../schemas/auth.js'

declare module 'fastify' {
  interface FastifyInstance {
    usersRepository: ReturnType<typeof createUsersRepository>;
  }
}

export function createUsersRepository (fastify: FastifyInstance) {
  const knex = fastify.knex

  return {
    async findByEmail (email: string, trx?: Knex) {
      const user: Auth & { password: string } = await (trx ?? knex)('users')
        .select('id', 'username', 'password', 'email')
        .where({ email })
        .first()

      return user
    },

    async updatePassword (email: string, hashedPassword: string) {
      return knex('users')
        .update({ password: hashedPassword })
        .where({ email })
    },

    async findUserRolesByEmail (email: string, trx: Knex) {
      const roles: ({ name: string })[] = await trx('roles')
        .select('roles.name')
        .join('user_roles', 'roles.id', '=', 'user_roles.role_id')
        .join('users', 'user_roles.user_id', '=', 'users.id')
        .where('users.email', email)

      return roles
    }
  }
}

export default fp(
  async function (fastify: FastifyInstance) {
    const repo = createUsersRepository(fastify)
    fastify.decorate('usersRepository', repo)
  },
  {
    name: 'users-repository',
    dependencies: ['knex']
  }
)

import mysql, { FieldPacket } from 'mysql2/promise'
import path from 'node:path'
import fs from 'node:fs'
import Postgrator from 'postgrator'

interface PostgratorResult {
  rows: any;
  fields: FieldPacket[];
}

async function doMigration (): Promise<void> {
  const connection = await mysql.createConnection({
    multipleStatements: true,
    host: process.env.MYSQL_HOST,
    port: Number(process.env.MYSQL_PORT),
    database: process.env.MYSQL_DATABASE,
    user: process.env.MYSQL_USER,
    password: process.env.MYSQL_PASSWORD
  })

  try {
    const migrationDir = path.join(import.meta.dirname, '../migrations')

    if (!fs.existsSync(migrationDir)) {
      throw new Error(
        `Migration directory "${migrationDir}" does not exist. Skipping migrations.`
      )
    }

    const postgrator = new Postgrator({
      migrationPattern: path.join(migrationDir, '*'),
      driver: 'mysql',
      database: process.env.MYSQL_DATABASE,
      execQuery: async (query: string): Promise<PostgratorResult> => {
        const [rows, fields] = await connection.query(query)
        return { rows, fields }
      },
      schemaTable: 'schemaversion'
    })

    await postgrator.migrate()

    console.log('Migration completed!')
  } catch (err) {
    console.error(err)
  } finally {
    await connection.end().catch(err => console.error(err))
  }
}

doMigration()

import {
  FastifyPluginAsyncTypebox,
  Type
} from '@fastify/type-provider-typebox'
import { CredentialsSchema } from '../../../schemas/auth.js'

const plugin: FastifyPluginAsyncTypebox = async (fastify) => {
  const { usersRepository, passwordManager } = fastify
  fastify.post(
    '/login',
    {
      schema: {
        body: CredentialsSchema,
        response: {
          200: Type.Object({
            success: Type.Boolean(),
            message: Type.Optional(Type.String())
          }),
          401: Type.Object({
            message: Type.String()
          })
        },
        tags: ['Authentication']
      }
    },
    async function (request, reply) {
      const { email, password } = request.body

      return fastify.knex.transaction(async (trx) => {
        const user = await usersRepository.findByEmail(email, trx)

        if (user) {
          const isPasswordValid = await passwordManager.compare(
            password,
            user.password
          )
          if (isPasswordValid) {
            const roles = await usersRepository.findUserRolesByEmail(email, trx)

            request.session.user = {
              id: user.id,
              email: user.email,
              username: user.username,
              roles: roles.map((role) => role.name)
            }

            await request.session.save()

            return { success: true }
          }
        }

        reply.status(401)

        return { message: 'Invalid email or password.' }
      })
    }
  )
}

export default plugin

'use strict'

const fastifySession = require('@fastify/session')
const fastifyCookie = require('@fastify/cookie')
const fastifyFormbody = require('@fastify/formbody')

const { loginPage, defaultPage } = require('./html')

function plugin (instance, options, next) {
  // register the required plugins
  instance.register(fastifyFormbody)
  instance.register(fastifyCookie)
  instance.register(fastifySession, {
    cookieName: 'sessionId',
    secret: 'a secret with minimum length of 32 characters',
    cookie: { maxAge: 1800000, secure: false }
  })

  // add a login route that returns a login page
  instance.get('/login', (request, reply) => {
    reply.type('text/html')
    reply.send(loginPage())
  })

  // add a login route that handles the actual login
  instance.post('/login', (request, reply) => {
    const { email, password } = request.body

    if (password === 'abcdef') {
      request.session.authenticated = true
      reply.type('text/html')
      reply.send(defaultPage(true))
    } else {
      reply.redirect('/login', 401)
    }
  });

  instance.get('/', (request, reply) => {
    reply.type('text/html')
    reply.send(defaultPage(request.session.authenticated))
  });

  // add a logout route
  instance.get('/logout', (request, reply) => {
    if (request.session.authenticated) {
      request.session.destroy((err) => {
        if (err) {
          reply.status(500)
          reply.send('Internal Server Error')
        } else {
          reply.redirect('/')
        }
      })
    } else {
      reply.redirect('/')
    }
  });

  next()
}

module.exports = plugin

'use strict'

const winston = require('winston')

// Create custom logger
const loggerInstance = winston.createLogger({
  // Define levels required by Fastify (by default winston has verbose level and does not have trace)
  levels: {
    fatal: 0,
    error: 1,
    warn: 2,
    info: 3,
    trace: 4,
    debug: 5
  },
  // Setup log level
  level: 'info',
  // Setup logs format
  format: winston.format.json(),
  // Define transports to write logs, it could be http, file or console
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'combined.log' })
  ]
})

// create a fastify instance to run and specify logger
const fastify = require('fastify')({ loggerInstance })

fastify.get('/hello', (req, reply) => {
  fastify.log.info('Sending hello')

  reply.send({ greet: 'hello' })
})

fastify.setNotFoundHandler((request, reply) => {
  fastify.log.debug('Route not found: ', request.req.url)

  reply.status(404).send({ message: 'Not found' })
})

fastify.setErrorHandler((error, request, reply) => {
  fastify.log.debug(`Request url: `, request.req.url)
  fastify.log.debug(`Payload: `, request.body)
  fastify.log.error(`Error occurred: `, error)

  reply.status(500).send({ message: 'Error occurred during request' })
})

fastify.listen({port: 3000})

import { Options } from 'fast-json-stringify'

type FastJsonStringifyFactory = () => SerializerSelector.SerializerFactory

declare namespace SerializerSelector {
  export type SerializerFactory = (
    externalSchemas?: unknown,
    options?: Options
  ) => SerializerCompiler

  export type SerializerCompiler = (routeDef: RouteDefinition) => Serializer
  export type Serializer = (doc: any) => string

  export type RouteDefinition = {
    method: string;
    url: string;
    httpStatus: string;
    schema?: unknown;
  }

  export type StandaloneOptions = StandaloneOptionsReadModeOn | StandaloneOptionsReadModeOff

  export type StandaloneOptionsReadModeOn = {
    readMode: true;
    restoreFunction?(opts: RouteDefinition): Serializer;
  }

  export type StandaloneOptionsReadModeOff = {
    readMode?: false | undefined;
    storeFunction?(opts: RouteDefinition, schemaSerializationCode: string): void;
  }

  export type { Options }
  export const SerializerSelector: FastJsonStringifyFactory
  export function StandaloneSerializer (options: StandaloneOptions): SerializerFactory

  export { SerializerSelector as default }
}

declare function SerializerSelector (...params: Parameters<FastJsonStringifyFactory>): ReturnType<FastJsonStringifyFactory>
export = SerializerSelector

